import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import logout from "../utils/logout";
import "./studentdashboard.css";

export default function StudentDashboard() {
  const navigate = useNavigate();
  const studentId = localStorage.getItem("userId"); // assuming stored at login
  const [activeTab, setActiveTab] = useState("project");
  const [requests, setRequests] = useState([]);

  const [formData, setFormData] = useState({
    project_title: "",
    time_required: "",
    domain: "",
    description: "",
    mentor_id: "",
  });

  const loadRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5050/api/mentor-requests/student/${studentId}`
      );
      setRequests(res.data || []);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    if (!studentId) {
      navigate("/login");
      return;
    }
    loadRequests();
  }, []);

  const handleChange = (e) =>
    setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5050/api/mentor-requests", {
        student_id: studentId,
        mentor_id: formData.mentor_id,
        project_title: formData.project_title,
        description: formData.description,
        domain: formData.domain,
        time_required: formData.time_required,
      });
      alert("Project request submitted successfully!");
      setFormData({
        project_title: "",
        time_required: "",
        domain: "",
        description: "",
        mentor_id: "",
      });
      loadRequests();
    } catch (err) {
      alert("Error submitting request.");
    }
  };

  return (
    <div className="student-dashboard">
      <div className="header">
        <h2>Student Dashboard</h2>
        <button onClick={() => logout(navigate)}>Logout</button>
      </div>

      <div className="tabs">
        {["project", "requests"].map((tab) => (
          <button
            key={tab}
            className={activeTab === tab ? "active" : ""}
            onClick={() => setActiveTab(tab)}
          >
            {tab.toUpperCase()}
          </button>
        ))}
      </div>

      {activeTab === "project" && (
        <div className="project-form">
          <h3>Submit Project Request</h3>
          <form onSubmit={handleSubmit}>
            <input
              name="project_title"
              value={formData.project_title}
              onChange={handleChange}
              placeholder="Project Title"
              required
            />
            <input
              name="time_required"
              value={formData.time_required}
              onChange={handleChange}
              placeholder="Time Required (weeks)"
            />
            <input
              name="domain"
              value={formData.domain}
              onChange={handleChange}
              placeholder="Domain"
              required
            />
            <textarea
              name="description"
              value={formData.description}
              onChange={handleChange}
              placeholder="Project Description"
              required
            ></textarea>
            <input
              name="mentor_id"
              value={formData.mentor_id}
              onChange={handleChange}
              placeholder="Mentor ID"
              required
            />
            <button type="submit">Submit</button>
          </form>
        </div>
      )}

      {activeTab === "requests" && (
        <div className="requests-list">
          <h3>Your Requests</h3>
          {requests.length === 0 ? (
            <p>No requests yet.</p>
          ) : (
            requests.map((r) => (
              <div key={r.id} className="card">
                <h4>{r.project_title}</h4>
                <p><b>Domain:</b> {r.domain}</p>
                <p><b>Mentor:</b> {r.mentor_name}</p>
                <p><b>Status:</b> {r.status}</p>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}
